/**
 * Get an icon component by ID
 */
export const getAzureIcon = (id: string): IconComponent | undefined => {
  return azureIconMap[id];
};

/**
 * List all available AZURE icon IDs
 */
export const listAzureIcons = (): string[] => {
  return Object.keys(azureIconMap);
};

export default azureIconMap;
